mapper.select:
SELECT id, username, password_hash, status, role, last_login_at
FROM HC_user
WHERE username = #{username}

mapper.update:
UPDATE HC_user
SET last_login_at = NOW()
WHERE username = #{username}

UPDATE HC_user
SET status = 'INACTIVE'
WHERE username = #{username}

mapper.select:
SELECT refresh_token_hash
FROM HC_refresh_token
WHERE refresh_token_hash = #{refreshToken}

mapper.delete:
DELETE FROM HC_refresh_token
WHERE user_id = (
  SELECT id
  FROM HC_user
  WHERE username = #{username}
)

mapper.select:
SELECT username
FROM HC_user
WHERE id = #{userId}
